bool myConstantPropagation(Function &Foo) {
  if (Foo.empty())
    return false;

  bool Modified = false;

  // Collect all instructions in RPO order
  ReversePostOrderTraversal<Function> RPO(Foo);
  SmallVector<Instruction*, 64> Worklist;

  for (BasicBlock *BB : RPO) {
    for (Instruction &I : *BB) {
      if (auto *BO = dyn_cast<BinaryOperator>(&I)) {
        Worklist.push_back(BO);
      }
    }
  }

  // Process worklist
  for (size_t i = 0; i < Worklist.size(); ++i) {
    Instruction *I = Worklist[i];

    // Skip already erased instructions
    if (I->use_empty() && !I->getParent())
      continue;

    auto *BO = dyn_cast<BinaryOperator>(I);
    if (!BO)
      continue;

    auto *Op0 = dyn_cast<ConstantInt>(BO->getOperand(0));
    auto *Op1 = dyn_cast<ConstantInt>(BO->getOperand(1));

    if (!Op0 || !Op1)
      continue;

    const APInt &V0 = Op0->getValue();
    const APInt &V1 = Op1->getValue();

    APInt Result(V0.getBitWidth(), 0);
    bool Folded = true;

    switch (BO->getOpcode()) {
    case Instruction::Add: Result = V0 + V1; break;
    case Instruction::Sub: Result = V0 - V1; break;
    case Instruction::Mul: Result = V0 * V1; break;
    case Instruction::SDiv:
      if (V1 == 0) continue;
      Result = V0.sdiv(V1);
      break;
    case Instruction::UDiv:
      if (V1 == 0) continue;
      Result = V0.udiv(V1);
      break;
    case Instruction::Shl:  Result = V0.shl(V1); break;
    case Instruction::LShr: Result = V0.lshr(V1); break;
    case Instruction::AShr: Result = V0.ashr(V1); break;
    case Instruction::And:  Result = V0 & V1; break;
    case Instruction::Or:   Result = V0 | V1; break;
    case Instruction::Xor:  Result = V0 ^ V1; break;
    default: Folded = false; break;
    }

    if (!Folded)
      continue;

    ConstantInt *NewC = ConstantInt::get(BO->getContext(), Result);
    BO->replaceAllUsesWith(NewC);
    BO->eraseFromParent();
    Modified = true;
  }

  return Modified;
}
```

